import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import './AuthPage.css';

const ERROR_MAP = {
  'auth/user-not-found': 'No account found with this email.',
  'auth/wrong-password': 'Incorrect password.',
  'auth/invalid-credential': 'Email or password is incorrect.',
  'auth/email-already-in-use': 'This email is already registered.',
  'auth/weak-password': 'Password must be at least 6 characters.',
  'auth/invalid-email': 'Please enter a valid email address.',
  'auth/popup-closed-by-user': 'Sign-in window was closed.',
  'auth/popup-blocked': 'Popup was blocked. Please allow popups for this site.',
  'auth/too-many-requests': 'Too many attempts. Try again later.',
  'auth/network-request-failed': 'Network error. Check your connection.',
};

export default function AuthPage() {
  const { signInWithGoogle, signInWithEmail, signUpWithEmail } = useAuth();
  const [mode, setMode] = useState('signin');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  function parseError(e) {
    return ERROR_MAP[e.code] || `Something went wrong. (${e.code || e.message})`;
  }

  async function handleGoogle() {
    setError(''); setLoading(true);
    try { await signInWithGoogle(); }
    catch (e) { setError(parseError(e)); }
    setLoading(false);
  }

  async function handleSubmit() {
    setError('');
    if (mode === 'signup' && !name.trim()) return setError('Please enter your name.');
    if (!email.trim()) return setError('Please enter your email.');
    if (!password) return setError('Please enter a password.');
    setLoading(true);
    try {
      if (mode === 'signin') await signInWithEmail(email, password);
      else await signUpWithEmail(email, password, name.trim());
    } catch (e) { setError(parseError(e)); }
    setLoading(false);
  }

  function toggle() { setMode(m => m === 'signin' ? 'signup' : 'signin'); setError(''); }

  return (
    <div className="auth-root">
      <div className="auth-grid-bg" />

      <div className="auth-card fade-in">
        <div className="auth-logo">
          <div className="auth-logo-mark">৳</div>
          <span className="auth-logo-text">Taka<strong>Tracker</strong></span>
        </div>
        <p className="auth-tagline">Plan components. Compare prices.<br />Build together.</p>

        <button className="auth-google-btn" onClick={handleGoogle} disabled={loading}>
          <GoogleSVG />
          Continue with Google
        </button>

        <div className="auth-or"><span>or</span></div>

        <div className="auth-fields">
          {mode === 'signup' && (
            <input
              className="auth-input" placeholder="Your name"
              value={name} onChange={e => setName(e.target.value)}
              autoComplete="name"
            />
          )}
          <input
            className="auth-input" type="email" placeholder="Email address"
            value={email} onChange={e => setEmail(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSubmit()}
            autoComplete="email"
          />
          <input
            className="auth-input" type="password" placeholder="Password"
            value={password} onChange={e => setPassword(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSubmit()}
            autoComplete={mode === 'signup' ? 'new-password' : 'current-password'}
          />
        </div>

        {error && <div className="auth-error">{error}</div>}

        <button className="auth-submit" onClick={handleSubmit} disabled={loading}>
          {loading ? <span className="auth-spinner" /> : mode === 'signin' ? 'Sign In' : 'Create Account'}
        </button>

        <button className="auth-toggle" onClick={toggle}>
          {mode === 'signin'
            ? "Don't have an account? Create one →"
            : 'Already have an account? Sign in →'}
        </button>
      </div>

      <p className="auth-footer-note">Designed in ST98HQ · Made by Srestho</p>
    </div>
  );
}

function GoogleSVG() {
  return (
    <svg width="18" height="18" viewBox="0 0 24 24" style={{ flexShrink: 0 }}>
      <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
      <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
      <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
      <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
    </svg>
  );
}
