import React, { useState } from 'react';
import { Plus, FolderOpen, Trash2, ChevronRight, Cpu, Calendar, Package, Users } from 'lucide-react';
import { createProject, deleteProject } from '../hooks/useProjects';
import './ProjectList.css';

export default function ProjectList({ projects, loading, currentUser, onSelect }) {
  const [creating, setCreating] = useState(false);
  const [name, setName] = useState('');
  const [desc, setDesc] = useState('');
  const [busy, setBusy] = useState(false);
  const [deleteId, setDeleteId] = useState(null);

  async function handleCreate() {
    if (!name.trim() || busy) return;
    setBusy(true);
    try {
      await createProject({
        name: name.trim(),
        description: desc.trim(),
        uid: currentUser.uid,
        userEmail: currentUser.email,
        userName: currentUser.displayName || currentUser.email,
      });
      setName(''); setDesc(''); setCreating(false);
    } catch (e) { console.error(e); }
    setBusy(false);
  }

  async function handleDelete(id) {
    try { await deleteProject(id); } catch (e) { console.error(e); }
    setDeleteId(null);
  }

  function getTotalBudget(project) {
    let total = 0;
    for (const comp of project.components || []) {
      const storeKey = comp.selectedStore;
      if (comp.prices?.length > 0) {
        const match = storeKey ? comp.prices.find(p => p.store === storeKey) : null;
        const price = match ? match.price : Math.min(...comp.prices.map(p => p.price));
        total += price * (comp.quantity || 1);
      }
    }
    return total;
  }

  const myProjects = projects.filter(p => p.ownerId === currentUser.uid);
  const sharedProjects = projects.filter(p => p.ownerId !== currentUser.uid);

  return (
    <div className="pl-root fade-in">
      <div className="pl-hero">
        <div className="pl-hero-badge mono">PLAN SHOPPING</div>
        <h1 className="pl-hero-title">Your Build Projects</h1>
        <p className="pl-hero-sub">Plan components, compare store prices in Taka, and share your purchase checklist.</p>
        <button className="btn-primary" onClick={() => setCreating(true)}>
          <Plus size={16} /> New Project
        </button>
      </div>

      {creating && (
        <div className="pl-create-card fade-in">
          <h3 className="pl-create-title">New Project</h3>
          <input
            autoFocus
            placeholder="Project name (e.g. Quad Drone v1)"
            value={name}
            onChange={e => setName(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleCreate()}
            className="pl-input"
          />
          <textarea
            placeholder="Description (optional)"
            value={desc}
            onChange={e => setDesc(e.target.value)}
            className="pl-input pl-textarea"
            rows={2}
          />
          <div className="pl-create-actions">
            <button className="btn-primary" onClick={handleCreate} disabled={busy || !name.trim()}>
              {busy ? 'Creating...' : 'Create Project'}
            </button>
            <button className="btn-ghost" onClick={() => { setCreating(false); setName(''); setDesc(''); }}>Cancel</button>
          </div>
        </div>
      )}

      {loading && (
        <div className="pl-loading">
          <div className="pl-loading-dots"><span/><span/><span/></div>
          <p>Loading projects...</p>
        </div>
      )}

      {!loading && projects.length === 0 && !creating && (
        <div className="pl-empty">
          <div className="pl-empty-icon"><Cpu size={40} /></div>
          <p>No projects yet. Create your first build project!</p>
        </div>
      )}

      {!loading && myProjects.length > 0 && (
        <ProjectSection
          title="My Projects"
          projects={myProjects}
          currentUser={currentUser}
          deleteId={deleteId}
          setDeleteId={setDeleteId}
          onSelect={onSelect}
          onDelete={handleDelete}
          getTotalBudget={getTotalBudget}
        />
      )}

      {!loading && sharedProjects.length > 0 && (
        <ProjectSection
          title="Shared With Me"
          projects={sharedProjects}
          currentUser={currentUser}
          deleteId={deleteId}
          setDeleteId={setDeleteId}
          onSelect={onSelect}
          onDelete={handleDelete}
          getTotalBudget={getTotalBudget}
          shared
        />
      )}
    </div>
  );
}

function ProjectSection({ title, projects, currentUser, deleteId, setDeleteId, onSelect, onDelete, getTotalBudget, shared }) {
  return (
    <div className="pl-section">
      <div className="pl-section-header">
        {shared && <Users size={13} />}
        <span>{title}</span>
        <span className="pl-section-count">{projects.length}</span>
      </div>
      <div className="pl-grid">
        {projects.map((project, i) => {
          const budget = getTotalBudget(project);
          const comps = project.components?.length || 0;
          const date = project.createdAt?.seconds
            ? new Date(project.createdAt.seconds * 1000).toLocaleDateString('en-BD', { day: 'numeric', month: 'short', year: 'numeric' })
            : 'Just now';
          const memberCount = Object.keys(project.members || {}).length;
          const isOwner = project.ownerId === currentUser.uid;

          return (
            <div
              key={project.id}
              className="pl-card fade-in"
              style={{ animationDelay: `${i * 0.04}s` }}
            >
              <div className="pl-card-header">
                <div className="pl-card-icon"><FolderOpen size={18} /></div>
                {isOwner && (
                  <button
                    className="pl-delete-btn"
                    onClick={e => { e.stopPropagation(); setDeleteId(project.id); }}
                  >
                    <Trash2 size={14} />
                  </button>
                )}
              </div>
              <h2 className="pl-card-name" onClick={() => onSelect(project.id)}>{project.name}</h2>
              {project.description && <p className="pl-card-desc">{project.description}</p>}
              <div className="pl-card-meta">
                <span className="pl-meta-item"><Package size={12} /> {comps} component{comps !== 1 ? 's' : ''}</span>
                <span className="pl-meta-item"><Calendar size={12} /> {date}</span>
                {memberCount > 1 && <span className="pl-meta-item pl-meta-collab"><Users size={12} /> {memberCount}</span>}
              </div>
              {budget > 0 && (
                <div className="pl-card-budget mono">
                  ৳{budget.toLocaleString('en-BD')}
                  <span className="pl-budget-label">est. total</span>
                </div>
              )}
              <button className="pl-open-btn" onClick={() => onSelect(project.id)}>
                Open Project <ChevronRight size={14} />
              </button>

              {deleteId === project.id && (
                <div className="pl-confirm-overlay" onClick={e => e.stopPropagation()}>
                  <p>Delete <strong>{project.name}</strong>?<br/><span style={{fontSize:'12px',opacity:.6}}>This cannot be undone.</span></p>
                  <div className="pl-confirm-btns">
                    <button className="btn-danger" onClick={() => onDelete(project.id)}>Delete</button>
                    <button className="btn-ghost" onClick={() => setDeleteId(null)}>Cancel</button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
