// Returns a dynamic greeting based on time of day and a bit of randomness.
// firstName is the user's first name.

export function getGreeting(displayName) {
  const name = (displayName || '').split(' ')[0] || 'Maker';
  const hour = new Date().getHours();

  const pools = {
    dawn: [ // 4–6
      `Rise and grind, ${name}! 🌅`,
      `You're up early, ${name}. Coffee first?`,
      `Burning the early hours, ${name}?`,
      `The circuit never sleeps, huh ${name}?`,
    ],
    morning: [ // 7–11
      `Good morning, ${name}! ☀️`,
      `Fresh start, ${name}. Let's plan something great.`,
      `Morning, ${name}! What are we building today?`,
      `Hey ${name}, morning energy detected ⚡`,
      `Rise and build, ${name}!`,
    ],
    noon: [ // 12–13
      `Lunch break planning, ${name}? 🍛`,
      `Midday check-in, ${name}!`,
      `Hey ${name}, how's the build going?`,
      `Power up before the afternoon, ${name}.`,
    ],
    afternoon: [ // 14–17
      `Afternoon, ${name}! Still at it? 💪`,
      `How's the energy today, ${name}?`,
      `Making progress, ${name}?`,
      `Good afternoon, ${name}. The grind continues.`,
      `Hey ${name}, that drone won't build itself!`,
    ],
    evening: [ // 18–20
      `Evening mode, ${name} 🌆`,
      `Winding down or just getting started, ${name}?`,
      `Evening, ${name}! Good time to plan.`,
      `Hey ${name}, golden hour for building plans.`,
    ],
    night: [ // 21–23
      `Making lists as a night owl, ${name}? 🦉`,
      `Late night planning session, ${name}?`,
      `Night mode ON, ${name} 🌙`,
      `Burning the midnight oil, ${name}?`,
      `Still going strong, ${name}. Respect. 🌙`,
    ],
    midnight: [ // 0–3
      `It's past midnight, ${name}. Sleep is a component too 😅`,
      `Whoa, ${name} — real night owl hours.`,
      `The dedication is unreal, ${name} 🌌`,
      `${name}, even the ESP32 needs rest sometimes.`,
    ],
  };

  let pool;
  if (hour >= 4 && hour < 7)       pool = pools.dawn;
  else if (hour >= 7 && hour < 12) pool = pools.morning;
  else if (hour >= 12 && hour < 14) pool = pools.noon;
  else if (hour >= 14 && hour < 18) pool = pools.afternoon;
  else if (hour >= 18 && hour < 21) pool = pools.evening;
  else if (hour >= 21)              pool = pools.night;
  else                              pool = pools.midnight;

  return pool[Math.floor(Math.random() * pool.length)];
}
